function tryParseAndFixJSON(input) {
    try {
        return JSON.parse(input);
    } catch (e) {
        // 1. Common AI Error: Using single backslash for code syntax (\d, \s) instead of double (\\d, \\s)
        // Fix: Find backslashes NOT followed by valid JSON escape chars and double them.
        console.warn("JSON Parse failed, attempting Auto-Fix for Bad Escapes...");
        try {
            // Regex: Match \ NOT followed by [ " \ / b f n r t u ]
            const fixed = input.replace(/\\(?!["\\\/bfnrtu])/g, "\\\\");
            return JSON.parse(fixed);
        } catch (e2) {
            // If that fails, throw original error
            throw e;
        }
    }
}

