async function triggerBuild() {
    const workflowFile = prompt("Enter Workflow Filename:", "build.yml");
    if (!workflowFile) return;
    const branch = prompt("Branch to run on:", "conduit-dev");
    if (!branch) return;

    const toast = document.createElement('div');
    toast.innerText = `🚀 Triggering ${workflowFile} on ${branch}...`;
    toast.style.cssText = "position:fixed; bottom:100px; left:50%; transform:translateX(-50%); background:#22c55e; color:black; padding:10px 20px; border-radius:30px; z-index:9999;";
    document.body.appendChild(toast);

    try {
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'trigger_build', workflow_id: workflowFile, branch: branch })
        });
        const data = await res.json();
        toast.remove();
        if(data.success) { 
            alert("Workflow Dispatched!"); 
            // Sync workflows AND logs (to see dispatch entry)
            setTimeout(() => { loadWorkflows(); fetchState(false, true); }, 2000); 
        }
    } catch(e) { toast.remove(); alert("Error: " + e.message); }
}

