    const workflowFile = prompt("Enter Workflow Filename:", "build.yml");
    if (!workflowFile) return;
    const branch = prompt("Branch to run on:", "conduit-dev");
    if (!branch) return;

    const toast = document.createElement('div');
    toast.style.cssText = "position:fixed; bottom:100px; left:50%; transform:translateX(-50%); background:#333; color:white; padding:10px 20px; border-radius:30px; z-index:9999; font-size:13px; box-shadow:0 4px 15px rgba(0,0,0,0.5); display:flex; align-items:center; gap:10px;";
    toast.innerHTML = `<span style="animation:pulse 1s infinite">🧬</span> Scanning project syntax...`;
    document.body.appendChild(toast);

    try {
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ 
                action: 'trigger_build', 
                workflow_id: workflowFile, 
                branch: branch,
                validate_pre_build: true // Enable Syntax Guard
            })
        });
        const data = await res.json();

        if (data.validation_error) {
            toast.style.background = "var(--danger)";
            toast.innerHTML = `⚠️ Syntax Error Detected`;
            setTimeout(() => toast.remove(), 3000);

            // Show details in an alert or modal
            alert(`Build Aborted: Syntax Error Detected!\n\n${data.error}`);
            return;
        }

        if(data.success) { 
            toast.style.background = "var(--prod)";
            toast.style.color = "black";
            toast.innerHTML = `🚀 Dispatched: ${workflowFile}`;
            setTimeout(() => toast.remove(), 2500);

            // Sync workflows AND logs (to see dispatch entry)
            setTimeout(() => { loadWorkflows(); fetchState(false, true); }, 2000); 
        } else {
