package com.getyetek.notify

import okhttp3.MediaType.Companion.toMediaType
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.RequestBody.Companion.toRequestBody
import org.json.JSONObject
import java.util.concurrent.TimeUnit

object ApiHelper {
    private const val SUPABASE_URL = "https://xvldfsmxskhemkslsbym.supabase.co/functions/v1/monitor-builds"
    private const val ANON_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inh2bGRmc214c2toZW1rc2xzYnltIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjI2ODgxNzksImV4cCI6MjA3ODI2NDE3OX0.5arqrx8Tt7v-hpXpo_ncoK4IX8th9IibxAuv93SSoOU"
    private val JSON = "application/json; charset=utf-8".toMediaType()

    private val client = OkHttpClient.Builder()
        .connectTimeout(15, TimeUnit.SECONDS)
        .readTimeout(15, TimeUnit.SECONDS)
        .build()

    // Fetch list of recent builds
    fun fetchBuildList(): List<BuildStatus> {
        val body = "{}".toRequestBody(JSON)
        val request = Request.Builder()
            .url(SUPABASE_URL)
            .addHeader("Authorization", "Bearer $ANON_KEY")
            .post(body)
            .build()

        try {
            client.newCall(request).execute().use { response ->
                if (!response.isSuccessful) return emptyList()
                val jsonStr = response.body?.string() ?: return emptyList()
                val json = JSONObject(jsonStr)
                val list = mutableListOf<BuildStatus>()

                val runs = json.optJSONArray("runs") ?: return emptyList()
                for (i in 0 until runs.length()) {
                    val obj = runs.getJSONObject(i)
                    list.add(BuildStatus(
                        runId = obj.optLong("id"),
                        runNumber = obj.optInt("run_number"),
                        name = obj.optString("name"),
                        status = obj.optString("status"),
                        conclusion = obj.optString("conclusion", "unknown"),
                        headCommit = obj.optString("head_commit"),
                        timestamp = obj.optString("timestamp")
                    ))
                }
                return list
            }
        } catch (e: Exception) {
            e.printStackTrace()
            return emptyList()
        }
    }

    // Fetch artifact URL for a specific run
    fun getArtifactUrl(runId: Long): String? {
        val jsonBody = JSONObject().put("action", "get_artifact").put("run_id", runId)
        val body = jsonBody.toString().toRequestBody(JSON)

        val request = Request.Builder()
            .url(SUPABASE_URL)
            .addHeader("Authorization", "Bearer $ANON_KEY")
            .post(body)
            .build()

        try {
            client.newCall(request).execute().use { response ->
                if (!response.isSuccessful) return null
                val jsonStr = response.body?.string() ?: return null
                val json = JSONObject(jsonStr)
                return if (json.optBoolean("success")) json.optString("url") else null
            }
        } catch (e: Exception) {
            return null
        }
    }

    // Keep old method for the Service (poller)
    fun fetchLatestBuild(): BuildStatus? {
        val list = fetchBuildList()
        return list.firstOrNull()
    }
}

data class BuildStatus(
    val runId: Long,
    val runNumber: Int,
    val name: String,
    val status: String,
    val conclusion: String,
    val headCommit: String = "",
    val timestamp: String = ""
)

package com.getyetek.notify

import android.content.Intent
import android.graphics.Color
import android.net.Uri
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Button
import android.widget.ImageView
import android.widget.TextView
import android.widget.Toast
import androidx.recyclerview.widget.RecyclerView
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import java.text.SimpleDateFormat
import java.util.Locale
import java.util.TimeZone

class BuildAdapter(private var builds: List<BuildStatus>) : RecyclerView.Adapter<BuildAdapter.BuildViewHolder>() {

    class BuildViewHolder(view: View) : RecyclerView.ViewHolder(view) {
        val icon: ImageView = view.findViewById(R.id.icon_status)
        val title: TextView = view.findViewById(R.id.text_title)
        val time: TextView = view.findViewById(R.id.text_time)
        val commit: TextView = view.findViewById(R.id.text_commit)
        val btnDownload: Button = view.findViewById(R.id.btn_download)
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): BuildViewHolder {
        val view = LayoutInflater.from(parent.context).inflate(R.layout.item_build, parent, false)
        return BuildViewHolder(view)
    }

    override fun onBindViewHolder(holder: BuildViewHolder, position: Int) {
        val build = builds[position]
        holder.title.text = "${build.name} #${build.runNumber}"
        holder.commit.text = build.headCommit
        holder.time.text = formatTime(build.timestamp)

        // Status Styling
        when (build.conclusion) {
            "success" -> {
                holder.icon.setImageResource(android.R.drawable.presence_online)
                holder.icon.setColorFilter(Color.parseColor("#4CAF50"))
                holder.btnDownload.visibility = View.VISIBLE
            }
            "failure" -> {
                holder.icon.setImageResource(android.R.drawable.presence_busy)
                holder.icon.setColorFilter(Color.parseColor("#F44336"))
                holder.btnDownload.visibility = View.GONE
            }
            else -> {
                holder.icon.setImageResource(android.R.drawable.presence_away)
                holder.icon.setColorFilter(Color.parseColor("#EAB308"))
                holder.btnDownload.visibility = View.GONE
            }
        }

        // Download Logic
        holder.btnDownload.setOnClickListener {
            holder.btnDownload.text = "Fetching..."
            holder.btnDownload.isEnabled = false

            CoroutineScope(Dispatchers.IO).launch {
                val url = ApiHelper.getArtifactUrl(build.runId)
                withContext(Dispatchers.Main) {
                    holder.btnDownload.text = "Download Artifact"
                    holder.btnDownload.isEnabled = true

                    if (url != null) {
                        val intent = Intent(Intent.ACTION_VIEW, Uri.parse(url))
                        intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                        try {
                            holder.itemView.context.startActivity(intent)
                        } catch (e: Exception) {
                            Toast.makeText(holder.itemView.context, "No browser found", Toast.LENGTH_SHORT).show()
                        }
                    } else {
                        Toast.makeText(holder.itemView.context, "Artifact not found", Toast.LENGTH_SHORT).show()
                    }
                }
            }
        }
    }

    override fun getItemCount() = builds.size

    fun updateData(newData: List<BuildStatus>) {
        builds = newData
        notifyDataSetChanged()
    }

