package com.getyetek.notify

import android.app.DownloadManager
import android.content.Context
import android.content.Intent
import android.net.Uri
import android.os.Build
import android.os.Bundle
import android.os.Environment
import android.widget.Button
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView
import kotlinx.coroutines.*

class MainActivity : AppCompatActivity() {

    private lateinit var adapter: BuildAdapter
    private val scope = CoroutineScope(Dispatchers.Main)

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        val btnRefresh = findViewById<Button>(R.id.btn_refresh)
        val btnMonitor = findViewById<Button>(R.id.btn_monitor)
        val recycler = findViewById<RecyclerView>(R.id.recycler_builds)

        adapter = BuildAdapter(emptyList()) { build -> handleDownload(build) }
        recycler.layoutManager = LinearLayoutManager(this)
        recycler.adapter = adapter

        btnRefresh.setOnClickListener { loadBuilds() }

        btnMonitor.setOnClickListener {
             val intent = Intent(this, MonitorService::class.java)
             if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) startForegroundService(intent) else startService(intent)
             Toast.makeText(this, "Background Service Started", Toast.LENGTH_SHORT).show()
        }

        loadBuilds()
    }

    private fun loadBuilds() {
        scope.launch(Dispatchers.IO) {
            val runs = ApiHelper.fetchRuns()
            withContext(Dispatchers.Main) {
                if (runs.isEmpty()) Toast.makeText(this@MainActivity, "No builds found", Toast.LENGTH_SHORT).show()
                adapter.updateList(runs)
            }
        }
    }

    private fun handleDownload(build: BuildStatus) {
        Toast.makeText(this, "Analysing logs for APK...", Toast.LENGTH_SHORT).show()

        scope.launch(Dispatchers.IO) {
            // 1. Find the Job ID
            val jobId = ApiHelper.fetchBuildJobId(build.runId)
            if (jobId == null) {
                withContext(Dispatchers.Main) { 
                    Toast.makeText(this@MainActivity, "Could not find Build Job", Toast.LENGTH_SHORT).show()
                    adapter.notifyDataSetChanged() // Reset button text
                }
                return@launch
            }

            // 2. Scan Logs for URL
            val url = ApiHelper.fetchArtifactUrl(jobId)
            withContext(Dispatchers.Main) {
                if (url != null) {
                    startDownload(url, build.runNumber)
                } else {
                    Toast.makeText(this@MainActivity, "Artifact URL not found in logs", Toast.LENGTH_LONG).show()
                }
                adapter.notifyDataSetChanged() // Reset button
            }
        }
    }

    private fun startDownload(url: String, runNumber: Int) {
        try {
            val request = DownloadManager.Request(Uri.parse(url))
                .setTitle("Notify App Build #$runNumber")
                .setDescription("Downloading APK from GitHub Actions...")
                .setNotificationVisibility(DownloadManager.Request.VISIBILITY_VISIBLE_NOTIFY_COMPLETED)
                .setDestinationInExternalPublicDir(Environment.DIRECTORY_DOWNLOADS, "notify-build-$runNumber.zip")
                .setAllowedOverMetered(true)
                .setAllowedOverRoaming(true)

            val dm = getSystemService(Context.DOWNLOAD_SERVICE) as DownloadManager
            dm.enqueue(request)
            Toast.makeText(this, "Download Started!", Toast.LENGTH_SHORT).show()
        } catch (e: Exception) {
            Toast.makeText(this, "Download Failed: ${e.message}", Toast.LENGTH_LONG).show()
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        scope.cancel()
    }
}

