package com.getyetek.notify

import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.Service
import android.content.Context
import android.content.Intent
import android.os.Build
import android.os.IBinder
import androidx.core.app.NotificationCompat
import kotlinx.coroutines.*

class MonitorService : Service() {

    private val serviceScope = CoroutineScope(Dispatchers.IO + Job())
    private var isMonitoring = false

    // AUTO-KILL LOGIC
    private var lastActivityTime = 0L
    private val TIMEOUT_MS = 30 * 60 * 1000 // 30 Minutes

    companion object {
        const val CHANNEL_ID = "build_monitor_channel"
        const val PREFS_NAME = "BuildPrefs"
        const val KEY_LAST_ID = "last_notified_id"
        const val NOTIFICATION_ID_FOREGROUND = 1
    }

    override fun onBind(intent: Intent?): IBinder? = null

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        if (!isMonitoring) {
            createNotificationChannel()

            // Reset timer on start
            lastActivityTime = System.currentTimeMillis()

            val notification = NotificationCompat.Builder(this, CHANNEL_ID)
                .setContentTitle("Build Watcher Active")
                .setContentText("Auto-kill in 30m if idle")
                .setSmallIcon(android.R.drawable.ic_popup_sync)
                .build()

            startForeground(NOTIFICATION_ID_FOREGROUND, notification)
            isMonitoring = true
            startPolling()
        }
        return START_STICKY
    }

    private fun startPolling() {
        serviceScope.launch {
            while (isMonitoring) {
                // 1. CHECK TIMEOUT
                val timeSinceLastBuild = System.currentTimeMillis() - lastActivityTime
                if (timeSinceLastBuild > TIMEOUT_MS) {
                    notifyTimeout()
                    stopSelf() // Kill the service
                    break
                }

                // 2. POLL API
                try {
                    val result = ApiHelper.fetchBuildStatus()
                    if (result != null) {
                        checkAndNotify(result)
                    }
                } catch (e: Exception) {
                    e.printStackTrace()
                }

                // 3. WAIT (30s)
                delay(30_000)
            }
        }
    }

    private fun checkAndNotify(build: BuildStatus) {
        val prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        val lastId = prefs.getLong(KEY_LAST_ID, -1)

        // If we found a NEW build that is COMPLETED
        if (build.runId > lastId && build.status == "completed") {
            sendAlert(build)
            prefs.edit().putLong(KEY_LAST_ID, build.runId).apply()

            // RESET AUTO-KILL TIMER
            lastActivityTime = System.currentTimeMillis()
            updateNotificationText("Last build: #${build.runNumber} (Timer Reset)")
        }
    }

    private fun updateNotificationText(text: String) {
        val notification = NotificationCompat.Builder(this, CHANNEL_ID)
            .setContentTitle("Build Watcher Active")
            .setContentText(text)
            .setSmallIcon(android.R.drawable.ic_popup_sync)
            .build()
        val manager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
        manager.notify(NOTIFICATION_ID_FOREGROUND, notification)
    }

    private fun sendAlert(build: BuildStatus) {
        val isSuccess = build.conclusion == "success"
        val title = if (isSuccess) "Build Success!" else "Build Failed"
        val color = if (isSuccess) 0xFF4CAF50.toInt() else 0xFFF44336.toInt()
        val icon = if (isSuccess) android.R.drawable.stat_sys_download_done else android.R.drawable.stat_notify_error

        val notification = NotificationCompat.Builder(this, CHANNEL_ID)
            .setContentTitle(title)
            .setContentText("${build.name} #${build.runNumber}")
            .setSmallIcon(icon)
            .setColor(color)
            .setPriority(NotificationCompat.PRIORITY_MAX)
            .setDefaults(NotificationCompat.DEFAULT_ALL)
            .setAutoCancel(true)
            .build()

        val manager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
        manager.notify(build.runId.toInt(), notification)
    }

    private fun notifyTimeout() {
        val notification = NotificationCompat.Builder(this, CHANNEL_ID)
            .setContentTitle("Monitoring Stopped")
            .setContentText("No new builds for 30m. Service killed to save battery.")
            .setSmallIcon(android.R.drawable.ic_menu_close_clear_cancel)
            .setAutoCancel(true)
            .build()
        val manager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
        manager.notify(999, notification)
    }

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                CHANNEL_ID,
                "Build Notifications",
                NotificationManager.IMPORTANCE_HIGH
            )
            val manager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
            manager.createNotificationChannel(channel)
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        isMonitoring = false
        serviceScope.cancel()
    }
}

