package com.gboard.clone

import android.content.Context
import org.json.JSONArray
import kotlinx.coroutines.ensureActive
import kotlin.coroutines.coroutineContext
import java.util.PriorityQueue
import android.util.Log
import java.io.File
import org.json.JSONObject
import kotlin.math.ln
import kotlin.math.abs

class TextPredictor(private val context: Context) {

    private val root = TrieNode()
    private val userDictFile = File(context.filesDir, "user_learning.json")
    var isLoaded = false

    // QWERTY ADJACENCY MAP
    private val keyboardLayout = mapOf(
        'q' to "wa", 'w' to "qase", 'e' to "wsdr", 'r' to "edft", 't' to "rfgy", 'y' to "tghu", 'u' to "yhji", 'i' to "ujko", 'o' to "iklp", 'p' to "ol",
        'a' to "qwsz", 's' to "qweadzx", 'd' to "ersfcxz", 'f' to "rtdgcv", 'g' to "tyfhvb", 'h' to "yvgjbn", 'j' to "uikhnm", 'k' to "iojlm", 'l' to "opk",
        'z' to "asx", 'x' to "zsdc", 'c' to "xdfv", 'v' to "cfgb", 'b' to "vghn", 'n' to "bhjm", 'm' to "njk"
    )

    class TrieNode {
        val children = HashMap<Char, TrieNode>()
        var isWord = false
        var score = 0.0
        var word: String? = null
    }

    fun loadDictionary() {
        Thread {
            try {
                val inputStream = context.resources.openRawResource(R.raw.dictionary)
                val jsonString = inputStream.bufferedReader().use { it.readText() }
                val jsonArray = JSONArray(jsonString)

                for (i in 0 until jsonArray.length()) {
                    val entry = jsonArray.getJSONArray(i)
                    val word = entry.getString(0)
                    val frequency = entry.getDouble(1)
                    // LOGARITHMIC SCORING: ln(freq + 1)
                    insert(word, ln(frequency + 1.0))
                }

                if (userDictFile.exists()) {
                    val userJson = JSONObject(userDictFile.readText())
                    val keys = userJson.keys()
                    while (keys.hasNext()) {
                        val word = keys.next()
                        val freq = userJson.getDouble(word)
                        // User words get a boost
                        insert(word, ln(freq + 1.0) + 2.0)
                    }
                }

                isLoaded = true
                Log.d("GboardClone", "Smart Dictionary Loaded (Log Scale)")
            } catch (e: Exception) {
                e.printStackTrace()
            }
        }.start()
    }

    fun learnWord(word: String) {
        if (word.length < 2) return

        var current = root
        for (char in word) {
            current = current.children.getOrPut(char) { TrieNode() }
        }

        // Increment score slightly in Log scale
        val oldScore = if (current.isWord) current.score else 0.0
        val newScore = oldScore + 0.2

        current.isWord = true
        current.score = newScore
        current.word = word

        saveUserWordAsync(word, 100.0) // Placeholder raw value for JSON
    }

    private fun saveUserWordAsync(word: String, score: Double) {
        Thread {
            try {
                val json = if (userDictFile.exists()) JSONObject(userDictFile.readText()) else JSONObject()
                json.put(word, score)
                userDictFile.writeText(json.toString())
            } catch (e: Exception) { e.printStackTrace() }
        }.start()
    }

    private fun insert(word: String, score: Double) {
        var current = root
        for (char in word) {
            current = current.children.getOrPut(char) { TrieNode() }
        }
        current.isWord = true
        current.score = score
        current.word = word
    }

    suspend fun predict(input: String, maxResults: Int = 3): List<String> {
        if (!isLoaded || input.isEmpty()) return emptyList()

        val combined = PriorityQueue<Pair<String, Double>> { a, b -> 
             if (b.second > a.second) 1 else -1 
        }

        val fuzzyMatches = if (input.isNotEmpty()) getFuzzyPredictions(input) else emptyList()
        fuzzyMatches.forEach { combined.add(it) }

        val output = mutableListOf<String>()
        val seen = HashSet<String>()

        while (output.size < maxResults && combined.isNotEmpty()) {
            val candidate = combined.poll()
            if (candidate != null && !seen.contains(candidate.first)) {
                output.add(candidate.first)
                seen.add(candidate.first)
            }
        }
        return output
    }

    private suspend fun getFuzzyPredictions(input: String): List<Pair<String, Double>> {
        val results = mutableListOf<Pair<String, Double>>()
        // Penalties are now relative to Log scores (e.g. 5.0 - 10.0 range)
        searchRecursive(root, input, 0, 0.0, results)
        return results
    }

    private suspend fun searchRecursive(node: TrieNode, target: String, index: Int, currentPenalty: Double, results: MutableList<Pair<String, Double>>) {
        if (index % 3 == 0) coroutineContext.ensureActive()

        // Threshold: 4.5 is a massive penalty in Log scale
        if (currentPenalty > 4.5) return

        // BASE CASE
        if (index == target.length) {
            if (node.isWord && node.word != null) {
                // PENALTY: Length Difference
                val lenDiff = abs(node.word!!.length - target.length)
                val lenPenalty = lenDiff * 1.5 

                val finalScore = node.score - currentPenalty - lenPenalty
                results.add(Pair(node.word!!, finalScore))
            }
            return
        }

        val targetChar = target[index].lowercaseChar()

        // 1. EXACT MATCH (Cost 0.0)
        if (node.children.containsKey(targetChar)) {
            searchRecursive(node.children[targetChar]!!, target, index + 1, currentPenalty, results)
        }

        // 2. SPATIAL MATCH (Cost 0.4) - Very cheap, encourages correction
        val neighbors = keyboardLayout[targetChar] ?: ""
        for (neighbor in neighbors) {
            if (node.children.containsKey(neighbor)) {
                searchRecursive(node.children[neighbor]!!, target, index + 1, currentPenalty + 0.4, results)
            }
        }

        // 3. INSERTION (Cost 2.5) - Expensive
        if (currentPenalty < 2.0) {
            searchRecursive(node, target, index + 1, currentPenalty + 2.5, results)
        }

        // 4. OMISSION (Cost 2.5) - Expensive
        if (currentPenalty < 2.0) {
            for ((_, childNode) in node.children) {
                 searchRecursive(childNode, target, index, currentPenalty + 2.5, results)
            }
        }
    }
}

