// ========================================================
// THEME ENGINE
// ========================================================

private fun applyTheme(root: View) {
    val bgColor = if (isDarkTheme) 0xFF141414.toInt() else 0xFFECECEC.toInt()
    val keyColor = if (isDarkTheme) 0xFF2D2F31.toInt() else 0xFFFFFFFF.toInt()
    val textColor = if (isDarkTheme) 0xFFFFFFFF.toInt() else 0xFF000000.toInt()
    val actionColor = 0xFF3D6B99.toInt() // Keep blue consistent

    // 1. Set Main Background
    root.setBackgroundColor(bgColor)
    root.findViewById<View>(R.id.keyboard_content)?.setBackgroundColor(bgColor)
    root.findViewById<View>(R.id.toolbar)?.setBackgroundColor(bgColor)
    root.findViewById<View>(R.id.row_suggestions)?.setBackgroundColor(bgColor)

    // 2. Recursive Color Applicator
    fun colorize(v: View) {
        if (v is ViewGroup) {
            for (i in 0 until v.childCount) {
                colorize(v.getChildAt(i))
            }

            // Check if this container is a Key (has the key background)
            // We identify keys by checking if they have the specific ID structure or tag, 
            // but simpler is checking if it has a background drawable we want to tint.
            // Since we can't easily check drawable resource ID, we rely on the fact that keys are ViewGroups (Frame/Linear) 
            // inside the rows, and they usually aren't the rows themselves.
            val bg = v.background
            if (bg != null && v.id != R.id.keyboard_content && v.id != R.id.toolbar && v.id != R.id.row_numbers) {
                 // Distinguish between Normal Keys and Action Keys (Enter)
                 if (v.id == R.id.key_enter || v.id == R.id.key_enter_sym || v.id == R.id.btn_enable || v.id == R.id.btn_select) {
                     bg.colorFilter = PorterDuffColorFilter(actionColor, PorterDuff.Mode.SRC_IN)
                 } else {
                     bg.colorFilter = PorterDuffColorFilter(keyColor, PorterDuff.Mode.SRC_IN)
                 }
            }
        }

        if (v is TextView) {
            // Don't colorize the suggestions strip text or toolbar icons roughly
            if (v.id != R.id.tool_settings && v.id != R.id.suggestion_1 && v.id != R.id.suggestion_2 && v.id != R.id.suggestion_3) {
                v.setTextColor(textColor)
            }
            // Suggestions text needs to be readable too
            if (v.id == R.id.suggestion_1 || v.id == R.id.suggestion_2 || v.id == R.id.suggestion_3) {
                v.setTextColor(textColor)
            }
        }

        if (v is ImageView) {
            // Tint Toolbar Icons
            v.setColorFilter(if (isDarkTheme) 0xFF9AA0A6.toInt() else 0xFF5F6368.toInt())
        }
    }

    colorize(root)
}

