package com.gboard.clone

import android.content.Context
import org.json.JSONArray
import org.json.JSONObject
import kotlinx.coroutines.ensureActive
import kotlin.coroutines.coroutineContext
import java.util.PriorityQueue
import android.util.Log
import java.io.File
import kotlin.math.ln
import kotlin.math.abs

class TextPredictor(private val context: Context) {

    private val englishRoot = TrieNode()
    private val amharicRoot = TrieNode()
    private val userDictFile = File(context.filesDir, "user_learning.json")

    var isEnglishLoaded = false
    var isAmharicLoaded = false

    private val keyboardLayout = mapOf(
        'q' to "wa", 'w' to "qase", 'e' to "wsdr", 'r' to "edft", 't' to "rfgy", 'y' to "tghu", 'u' to "yhji", 'i' to "ujko", 'o' to "iklp", 'p' to "ol",
        'a' to "qwsz", 's' to "qweadzx", 'd' to "ersfcxz", 'f' to "rtdgcv", 'g' to "tyfhvb", 'h' to "yvgjbn", 'j' to "uikhnm", 'k' to "iojlm", 'l' to "opk",
        'z' to "asx", 'x' to "zsdc", 'c' to "xdfv", 'v' to "cfgb", 'b' to "vghn", 'n' to "bhjm", 'm' to "njk"
    )

    class TrieNode {
        val children = HashMap<Char, TrieNode>()
        var isWord = false
        var score = 0.0
        var word: String? = null
    }

    fun loadDictionary() {
        Thread {
            try {
                val resId = context.resources.getIdentifier("dictionary", "raw", context.packageName)
                if (resId != 0) {
                    val inputStream = context.resources.openRawResource(resId)
                    val jsonString = inputStream.bufferedReader().use { it.readText() }
                    val jsonArray = JSONArray(jsonString)
                    for (i in 0 until jsonArray.length()) {
                        val entry = jsonArray.getJSONArray(i)
                        insert(englishRoot, entry.getString(0), ln(entry.getDouble(1) + 1.0))
                    }
                    isEnglishLoaded = true
                }
            } catch (e: Exception) { e.printStackTrace() }
        }.start()

        Thread {
            try {
                val resId = context.resources.getIdentifier("amharic_dictionary", "raw", context.packageName)
                if (resId != 0) {
                    val inputStream = context.resources.openRawResource(resId)
                    val wordsArray = JSONObject(inputStream.bufferedReader().use { it.readText() }).getJSONArray("words")
                    for (i in 0 until wordsArray.length()) {
                        val entry = wordsArray.getJSONObject(i)
                        insert(amharicRoot, entry.getString("word"), ln(entry.getDouble("frequency") + 1.0))
                    }
                    isAmharicLoaded = true
                }
            } catch (e: Exception) { e.printStackTrace() }
        }.start()

        Thread {
             try {
                 if (userDictFile.exists()) {
                    val userJson = JSONObject(userDictFile.readText())
                    val keys = userJson.keys()
                    while (keys.hasNext()) {
                        val word = keys.next()
                        insert(englishRoot, word, ln(userJson.getDouble(word) + 1.0) + 2.0)
                    }
                 }
             } catch (e: Exception) { e.printStackTrace() }
        }.start()
    }

    fun learnWord(word: String) {
        if (word.length < 2) return
        val isAmharicChar = word.any { it.code > 0x1200 }
        val targetRoot = if (isAmharicChar) amharicRoot else englishRoot
        var current = targetRoot
        for (char in word) current = current.children.getOrPut(char) { TrieNode() }
        current.isWord = true
        current.score = (if (current.isWord) current.score else 0.0) + 0.2
        current.word = word
        saveUserWordAsync(word, 100.0)
    }

    private fun saveUserWordAsync(word: String, score: Double) {
        Thread {
            try {
                val json = if (userDictFile.exists()) JSONObject(userDictFile.readText()) else JSONObject()
                json.put(word, score)
                userDictFile.writeText(json.toString())
            } catch (e: Exception) { e.printStackTrace() }
        }.start()
    }

    private fun insert(root: TrieNode, word: String, score: Double) {
        var current = root
        for (char in word) current = current.children.getOrPut(char) { TrieNode() }
        current.isWord = true
        current.score = score
        current.word = word
    }

    suspend fun predict(input: String, isAmharic: Boolean, maxResults: Int = 3): List<String> {
        if (input.isEmpty()) return emptyList()

        val root = if (isAmharic) amharicRoot else englishRoot
        if (isAmharic && !isAmharicLoaded) return emptyList()
        if (!isAmharic && !isEnglishLoaded) return emptyList()

        // SCORING PRIORITY QUEUE
        val combined = PriorityQueue<Pair<String, Double>> { a, b -> if (b.second > a.second) 1 else -1 }

        // 1. LITERAL EXACT MATCH (The God Mode check)
        // Does the input exist as a valid word? If yes, give it HUGE score.
        val exactScore = checkLiteralMatch(root, input)
        if (exactScore != null) {
            combined.add(Pair(input, 200.0)) // 200.0 beats everything
        }

        // 2. PREFIX COMPLETIONS (Extensions)
        // "we" -> "well", "went". Score = Natural Frequency (~5.0 to 12.0)
        val completions = getPrefixCompletions(root, input)
        completions.forEach { combined.add(it) }

        // 3. FUZZY SEARCH (Corrections)
        // "tgod" -> "this". Score = Natural Frequency - Penalty
        val fuzzyMatches = getFuzzyPredictions(root, input, useSpatial = !isAmharic)
        fuzzyMatches.forEach { combined.add(it) }

        val output = mutableListOf<String>()
        val seen = HashSet<String>()
        while (output.size < maxResults && combined.isNotEmpty()) {
            val candidate = combined.poll()
            if (candidate != null && !seen.contains(candidate.first)) {
                output.add(candidate.first)
                seen.add(candidate.first)
            }
        }
        return output
    }

    private fun checkLiteralMatch(root: TrieNode, input: String): Double? {
        var current = root
        for (char in input) {
            current = current.children[char] ?: return null
        }
        return if (current.isWord) current.score else null
    }

    private fun getPrefixCompletions(root: TrieNode, prefix: String): List<Pair<String, Double>> {
        var current = root
        for (char in prefix) {
            current = current.children[char] ?: return emptyList()
        }
        val results = mutableListOf<Pair<String, Double>>()
        collectWordsRecursive(current, results)
        return results
    }

    private fun collectWordsRecursive(node: TrieNode, results: MutableList<Pair<String, Double>>) {
        if (node.isWord && node.word != null) {
            results.add(Pair(node.word!!, node.score))
        }
        for ((_, child) in node.children) {
            collectWordsRecursive(child, results)
        }
    }

    private suspend fun getFuzzyPredictions(root: TrieNode, input: String, useSpatial: Boolean): List<Pair<String, Double>> {
        val results = mutableListOf<Pair<String, Double>>()
        val maxPenalty = if (useSpatial) 4.5 else 3.5 
        searchRecursive(root, input, 0, 0.0, results, useSpatial, maxPenalty)
        return results
    }

    private suspend fun searchRecursive(node: TrieNode, target: String, index: Int, currentPenalty: Double, results: MutableList<Pair<String, Double>>, useSpatial: Boolean, maxPenalty: Double) {
        if (index % 5 == 0) coroutineContext.ensureActive()

        if (currentPenalty > maxPenalty) return

        if (index == target.length) {
            if (node.isWord && node.word != null) {
                val lenDiff = abs(node.word!!.length - target.length)
                val lenMultiplier = if (useSpatial) 2.0 else 1.0 // Strong length penalty for English
                val finalScore = node.score - currentPenalty - (lenDiff * lenMultiplier)
                results.add(Pair(node.word!!, finalScore))
            }
            return
        }

        val targetChar = target[index].lowercaseChar()

        // EXACT PATH
        if (node.children.containsKey(targetChar)) {
            searchRecursive(node.children[targetChar]!!, target, index + 1, currentPenalty, results, useSpatial, maxPenalty)
        }

        // SPATIAL (English)
        if (useSpatial) {
            val neighbors = keyboardLayout[targetChar] ?: ""
            for (neighbor in neighbors) {
                if (node.children.containsKey(neighbor)) {
                    searchRecursive(node.children[neighbor]!!, target, index + 1, currentPenalty + 0.4, results, useSpatial, maxPenalty)
                }
            }
        }

        // EDITS
        val editCost = if (useSpatial) 2.5 else 1.5
        if (currentPenalty < 2.5) {
             // Insertion
             searchRecursive(node, target, index + 1, currentPenalty + editCost, results, useSpatial, maxPenalty)
             // Omission
             for ((_, child) in node.children) {
                 searchRecursive(child, target, index, currentPenalty + editCost, results, useSpatial, maxPenalty)
             }
        }
    }
}

