package com.gboard.clone

import android.content.Context
import android.util.Log
import org.json.JSONArray
import org.json.JSONObject
import kotlinx.coroutines.ensureActive
import kotlin.coroutines.coroutineContext
import java.util.PriorityQueue
import java.io.File
import kotlin.math.abs
import kotlin.math.ln

class TextPredictor(private val context: Context) {

    private val englishRoot = TrieNode()
    private val amharicRoot = TrieNode()
    private val userDictFile = File(context.filesDir, "user_learning.json")

    @Volatile private var isEnglishLoaded = false
    @Volatile private var isAmharicLoaded = false

    // QWERTY Adjacent keys map for Spatial correction
    private val keyboardLayout = mapOf(
        'q' to "wa", 'w' to "qase", 'e' to "wsdr", 'r' to "edft", 't' to "rfgy", 'y' to "tghu", 'u' to "yhji", 'i' to "ujko", 'o' to "iklp", 'p' to "ol",
        'a' to "qwsz", 's' to "qweadzx", 'd' to "ersfcxz", 'f' to "rtdgcv", 'g' to "tyfhvb", 'h' to "yvgjbn", 'j' to "uikhnm", 'k' to "iojlm", 'l' to "opk",
        'z' to "asx", 'x' to "zsdc", 'c' to "xdfv", 'v' to "cfgb", 'b' to "vghn", 'n' to "bhjm", 'm' to "njk"
    )

    class TrieNode {
        val children = HashMap<Char, TrieNode>()
        var isWord = false
        var score = -20.0 // Default low log-probability
        var word: String? = null
    }

    fun loadDictionary() {
        // 1. ENGLISH DICTIONARY (Log Frequencies)
        Thread {
            try {
                val resId = context.resources.getIdentifier("dictionary", "raw", context.packageName)
                if (resId != 0) {
                    val inputStream = context.resources.openRawResource(resId)
                    val jsonString = inputStream.bufferedReader().use { it.readText() }
                    val jsonArray = JSONArray(jsonString)

                    // FORMAT: [["word", -9.23], ["word2", -4.5]]
                    for (i in 0 until jsonArray.length()) {
                        val entry = jsonArray.getJSONArray(i)
                        val word = entry.getString(0).lowercase()
                        val freq = entry.getDouble(1)
                        // Use freq directly (it's already a log value like -9.23)
                        insert(englishRoot, word, freq)
                    }
                    isEnglishLoaded = true
                    Log.d("TextPredictor", "English Dictionary Loaded: ${jsonArray.length()} words")
                }
            } catch (e: Exception) {
                Log.e("TextPredictor", "English Load Failed", e)
            }
        }.start()

        // 2. AMHARIC DICTIONARY
        Thread {
            try {
                val resId = context.resources.getIdentifier("amharic_dictionary", "raw", context.packageName)
                if (resId != 0) {
                    val inputStream = context.resources.openRawResource(resId)
                    val json = JSONObject(inputStream.bufferedReader().use { it.readText() })
                    val wordsArray = json.getJSONArray("words")

                    for (i in 0 until wordsArray.length()) {
                        val entry = wordsArray.getJSONObject(i)
                        val word = entry.getString("word")
                        // Handle potential count vs log format safely
                        val rawFreq = entry.getDouble("frequency")
                        val score = if (rawFreq < 0) rawFreq else ln(rawFreq + 1.0)
                        insert(amharicRoot, word, score)
                    }
                    isAmharicLoaded = true
                }
            } catch (e: Exception) {
                e.printStackTrace()
            }
        }.start()

        // 3. USER LEARNING
        Thread {
             try {
                 if (userDictFile.exists()) {
                    val userJson = JSONObject(userDictFile.readText())
                    val keys = userJson.keys()
                    while (keys.hasNext()) {
                        val word = keys.next()
                        // Give user words a massive boost (+5.0 log scale is huge)
                        insert(englishRoot, word.lowercase(), 5.0)
                    }
                 }
             } catch (e: Exception) { e.printStackTrace() }
        }.start()
    }

    fun learnWord(word: String) {
        if (word.length < 2) return
        val lowerWord = word.lowercase()
        val isAmharicChar = word.any { it.code > 0x1200 }
        val targetRoot = if (isAmharicChar) amharicRoot else englishRoot

        var current = targetRoot
        for (char in lowerWord) current = current.children.getOrPut(char) { TrieNode() }

        current.isWord = true
        current.word = word // Store original casing if passed, or lower
        current.score = 5.0 // High priority for learned words

        saveUserWordAsync(lowerWord, 5.0)
    }

    private fun saveUserWordAsync(word: String, score: Double) {
        Thread {
            try {
                val json = if (userDictFile.exists()) JSONObject(userDictFile.readText()) else JSONObject()
                json.put(word, score)
                userDictFile.writeText(json.toString())
            } catch (e: Exception) { e.printStackTrace() }
        }.start()
    }

    private fun insert(root: TrieNode, word: String, score: Double) {
        var current = root
        for (char in word) {
            current = current.children.getOrPut(char) { TrieNode() }
        }
        current.isWord = true
        current.score = score
        current.word = word
    }

    suspend fun predict(input: String, isAmharic: Boolean, maxResults: Int = 3): List<String> {
        if (input.isEmpty()) return emptyList()
        val lowerInput = input.lowercase()

        val root = if (isAmharic) amharicRoot else englishRoot
        if (isAmharic && !isAmharicLoaded) return emptyList()
        if (!isAmharic && !isEnglishLoaded) return emptyList()

        // PriorityQueue orders by HIGHEST score first
        val candidates = PriorityQueue<Pair<String, Double>> { a, b -> b.second.compareTo(a.second) }

        // 1. EXACT MATCH (The God Mode Check)
        // We deliberately boost exact matches so they ALWAYS appear first if they exist.
        val exactScore = checkLiteralMatch(root, lowerInput)
        if (exactScore != null) {
            // Add a massive offset to the dictionary score to ensure it beats any fuzzy match
            candidates.add(Pair(input, exactScore + 100.0))
        }

        // 2. FUZZY & COMPLETION SEARCH
        // We run a robust recursive search that handles typos and completions
        val fuzzyResults = mutableListOf<Pair<String, Double>>()
        searchRecursive(
            node = root, 
            target = lowerInput, 
            index = 0, 
            cost = 0.0, 
            editCount = 0,
            results = fuzzyResults, 
            useSpatial = !isAmharic
        )

        fuzzyResults.forEach { candidates.add(it) }

        val output = mutableListOf<String>()
        val seen = HashSet<String>()

        // Deduplicate and Fill
        while (output.size < maxResults && candidates.isNotEmpty()) {
            val candidate = candidates.poll()
            if (candidate != null && !seen.contains(candidate.first)) {
                output.add(candidate.first)
                seen.add(candidate.first)
            }
        }
        return output
    }

    private fun checkLiteralMatch(root: TrieNode, input: String): Double? {
        var current = root
        for (char in input) {
            current = current.children[char] ?: return null
        }
        return if (current.isWord) current.score else null
    }

    // ROBUST RECURSIVE SEARCH (Damerau-Levenshtein inspired)
    private suspend fun searchRecursive(
        node: TrieNode, 
        target: String, 
        index: Int, 
        cost: Double, 
        editCount: Int,
        results: MutableList<Pair<String, Double>>, 
        useSpatial: Boolean
    ) {
        // Cooperative cancellation check
        if (index % 4 == 0) coroutineContext.ensureActive()

        val maxEdits = 2
        if (editCount > maxEdits) return

        // BASE CASE: End of Trie path (Prefix match or Word match)
        if (node.isWord) {
            // Calculate remaining characters in target as deletions
            val remainingChars = target.length - index
            val totalCost = cost + (remainingChars * 1.5) // Delete remaining input

            if (totalCost < 3.5) {
                // Score = Dictionary Score - Edit Penalty
                // We penalize the dictionary log-score (which is negative) by subtracting cost
                val finalScore = node.score - totalCost
                results.add(Pair(node.word!!, finalScore))
            }
        }

        // If we exhausted target but trie continues -> This is a Prefix Completion (e.g. "bui" -> "build")
        if (index >= target.length) {
             collectCompletions(node, results, cost)
             return
        }

        val targetChar = target[index]

        // 1. MATCH (Cost 0)
        if (node.children.containsKey(targetChar)) {
            searchRecursive(node.children[targetChar]!!, target, index + 1, cost, editCount, results, useSpatial)
        }

        // PRUNING: If cost is already high, don't branch into expensive edits
        if (cost > 3.0) return

        // 2. SPATIAL / SUBSTITUTION (Cost varies)
        if (useSpatial) {
            // Check neighbors (Spatial Typo)
            val neighbors = keyboardLayout[targetChar] ?: ""
            for (neighbor in neighbors) {
                if (node.children.containsKey(neighbor)) {
                    // Low cost for neighbor hit (0.5)
                    searchRecursive(node.children[neighbor]!!, target, index + 1, cost + 0.5, editCount + 1, results, useSpatial)
                }
            }
        }

        // 3. GENERIC SUBSTITUTION (Wrong key, not neighbor) -> Cost 1.5
        // Only try this if we haven't done too many edits
        if (editCount < maxEdits) {
            for ((char, childNode) in node.children) {
                if (char != targetChar) {
                    searchRecursive(childNode, target, index + 1, cost + 1.5, editCount + 1, results, useSpatial)
                }
            }
        }

        // 4. INSERTION (User typed extra char, skip it) -> Cost 2.0
        searchRecursive(node, target, index + 1, cost + 2.0, editCount + 1, results, useSpatial)

        // 5. OMISSION (User missed a char, skip trie node) -> Cost 2.0
        // Iterated in the loop above generally, but specifically:
        // We already iterated children in Substitution. We can interpret that as "Insert into target" logic too.
    }

    // Helper to perform a deep dive for completions without edits
    private fun collectCompletions(node: TrieNode, results: MutableList<Pair<String, Double>>, currentCost: Double) {
        if (results.size > 10) return // Optimization cap

        if (node.isWord) {
             // Simple prefix matches get a slight penalty based on length difference to encourage shorter, more relevant completions
             results.add(Pair(node.word!!, node.score - currentCost))
        }
        for ((_, child) in node.children) {
            collectCompletions(child, results, currentCost)
        }
    }
}

