package com.gboard.clone

import android.content.Context
import android.util.Log
import org.json.JSONArray
import org.json.JSONObject
import java.io.File
import java.util.Collections
import java.util.PriorityQueue
import kotlin.math.abs
import kotlin.math.min
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext

/**
 * SymSpell Implementation (Symmetric Delete Spelling Correction).
 * Replaces complex recursive search with fast, deterministic edit-distance Lookups.
 */
class TextPredictor(private val context: Context) {

    // CONFIGURATION
    // Max Edits: 2 covers 98% of human typos. Going to 3 is exponentially slower/heavier.
    private val MAX_EDIT_DISTANCE = 2
    private val PREFIX_LENGTH = 7

    // DATA STRUCTURES
    // lexicon: Map<Word, LogFrequency>. Higher value (closer to 0) = more frequent.
    private val lexicon = HashMap<String, Double>()
    // deletes: Map<DeletedSegment, List<CandidateWord>>
    private val deletes = HashMap<String, ArrayList<String>>()

    private val userDictFile = File(context.filesDir, "user_learning.json")
    @Volatile private var isReady = false

    fun loadDictionary() {
        Thread {
            try {
                val startTime = System.currentTimeMillis()

                // 1. LOAD ENGLISH (JSON Array: [["word", -9.23], ...])
                loadEnglishResource()

                // 2. LOAD AMHARIC (JSON Object: { "words": [...] })
                loadAmharicResource()

                // 3. LOAD USER WORDS
                loadUserHistory()

                isReady = true
                Log.d("SymSpell", "Loaded ${lexicon.size} words in ${System.currentTimeMillis() - startTime}ms")
            } catch (e: Exception) {
                Log.e("SymSpell", "Fatal Load Error", e)
            }
        }.start()
    }

    private fun loadEnglishResource() {
        val resId = context.resources.getIdentifier("dictionary", "raw", context.packageName)
        if (resId != 0) {
            val stream = context.resources.openRawResource(resId)
            val jsonStr = stream.bufferedReader().use { it.readText() }
            val jsonArray = JSONArray(jsonStr)

            for (i in 0 until jsonArray.length()) {
                val item = jsonArray.getJSONArray(i)
                val word = item.getString(0).lowercase()
                val score = item.getDouble(1) // Log score (e.g. -9.5)
                createDictionaryEntry(word, score)
            }
        }
    }

    private fun loadAmharicResource() {
        val resId = context.resources.getIdentifier("amharic_dictionary", "raw", context.packageName)
        if (resId != 0) {
            val stream = context.resources.openRawResource(resId)
            val json = JSONObject(stream.bufferedReader().use { it.readText() })
            val arr = json.getJSONArray("words")
            for (i in 0 until arr.length()) {
                val item = arr.getJSONObject(i)
                val word = item.getString("word")
                // Normalize Amharic score to match English log-scale roughly (0 to -15)
                val rawFreq = item.optDouble("frequency", 0.0)
                // Simple normalization if positive count
                val score = if (rawFreq > 0) kotlin.math.ln(rawFreq + 1) - 15.0 else -10.0
                createDictionaryEntry(word, score)
            }
        }
    }

    private fun loadUserHistory() {
        if (userDictFile.exists()) {
            try {
                val json = JSONObject(userDictFile.readText())
                val keys = json.keys()
                while (keys.hasNext()) {
                    val word = keys.next()
                    // User words get 'God Mode' score (+5.0)
                    createDictionaryEntry(word.lowercase(), 5.0)
                }
            } catch (e: Exception) { e.printStackTrace() }
        }
    }

    /**
     * THE CORE INDEXER
     * Generates all "deleted" versions of the word and maps them back to the original.
     * e.g. "build" -> maps "buid", "bild", "uild", etc. to "build"
     */
    private fun createDictionaryEntry(word: String, score: Double) {
        if (word.isEmpty()) return

        // 1. Add to Lexicon (The Truth)
        // Keep the highest score if duplicate exists
        val currentScore = lexicon[word] ?: -Double.MAX_VALUE
        if (score > currentScore) {
            lexicon[word] = score
        }

        // 2. Generate Deletes (The SymSpell Magic)
        // Only index if word is short enough to matter or we have RAM
        // Limit edits to MAX_EDIT_DISTANCE
        if (word.length <= MAX_EDIT_DISTANCE) {
            // Short words are their own deletes essentially
             addToDeletes(word, word)
        } else {
             val edits = HashSet<String>()
             getDeletesRecursive(word, 0, MAX_EDIT_DISTANCE, edits)
             for (delete in edits) {
                 addToDeletes(delete, word)
             }
        }
    }

    private fun addToDeletes(deleteKey: String, originalWord: String) {
        var list = deletes[deleteKey]
        if (list == null) {
            list = ArrayList()
            deletes[deleteKey] = list
        }
        // Deduplicate in list to save RAM
        if (!list.contains(originalWord)) {
            list.add(originalWord)
        }
    }

    // Recursive generator for deleted keys
    private fun getDeletesRecursive(word: String, depth: Int, maxDepth: Int, accumulator: HashSet<String>) {
        // Always add the word itself (Edit Dist 0)
        accumulator.add(word)

        if (depth >= maxDepth) return

        // Remove 1 char at a time
        for (i in 0 until word.length) {
            val sub = word.substring(0, i) + word.substring(i + 1)
            if (accumulator.add(sub)) {
                getDeletesRecursive(sub, depth + 1, maxDepth, accumulator)
            }
        }
    }

    /**
     * LEARN: Dynamic Updates
     */
    fun learnWord(word: String) {
        if (word.length < 2) return
        val lower = word.lowercase()
        // Instant in-memory update
        createDictionaryEntry(lower, 5.0)

        // Persist
        Thread {
            try {
                val json = if (userDictFile.exists()) JSONObject(userDictFile.readText()) else JSONObject()
                json.put(lower, 5.0)
                userDictFile.writeText(json.toString())
            } catch (e: Exception) { e.printStackTrace() }
        }.start()
    }

    /**
     * PREDICT: The Fast Lookup
     */
    suspend fun predict(input: String, isAmharic: Boolean, maxResults: Int = 3): List<String> {
        if (!isReady || input.isEmpty()) return emptyList()
        val lowerInput = input.lowercase()

        // Results Container: Map<Word, Score> to handle deduplication logic
        val candidates = HashMap<String, Double>()

        // 1. EXACT MATCH CHECK (Optimized)
        if (lexicon.containsKey(lowerInput)) {
            candidates[input] = 100.0 // Absolute win
        }

        // 2. SYM-SPELL LOOKUP
        // Generate deletes for the INPUT
        val inputDeletes = HashSet<String>()
        getDeletesRecursive(lowerInput, 0, MAX_EDIT_DISTANCE, inputDeletes)

        for (delete in inputDeletes) {
            val matches = deletes[delete]
            if (matches != null) {
                for (candidate in matches) {
                    // FILTRATION: We have a candidate, but we must verify the ACTUAL distance.
                    // SymSpell is a pre-filter. A 'delete' match doesn't guarantee distance <= 2 if we did multiple deletes.
                    // But here, since we generated deletes for both, the candidate is usually valid.

                    // Optimization: Skip if we already have a better score for this word
                    if (candidates.containsKey(candidate)) continue

                    val dictScore = lexicon[candidate] ?: -50.0

                    // Calculate Damerau-Levenshtein for ranking
                    // (We use a simpler version here for speed: Length Diff Penalty + Frequency)
                    val dist = abs(candidate.length - lowerInput.length)

                    // Score = LogFrequency - (Distance * Penalty)
                    // If input is "build", candidate "build" (Dist 0) -> Score -9.2
                    // If input is "buid", candidate "build" (Dist 1) -> Score -9.2 - 2.0 = -11.2
                    val finalScore = dictScore - (dist * 2.0)

                    candidates[candidate] = finalScore
                }
            }
        }

        // 3. SORT & RETURN
        val sorted = candidates.entries.sortedByDescending { it.value }

        return sorted.take(maxResults).map { 
            // Preserve casing: If candidate is in dictionary as lowercase, return as is.
            // If user typed Capitalized, we could adapt, but for now strict dict return is safer.
            it.key 
        }
    }
}

