// FIND JOB ID FOR A RUN
fun fetchBuildJobId(repo: String, runId: Long): Long? {
    val jsonBody = JSONObject().put("action", "fetch_jobs").put("run_id", runId).put("repo", repo)
    val request = Request.Builder()
        .url(SUPABASE_URL)
        .addHeader("Authorization", "Bearer $ANON_KEY")
        .post(jsonBody.toString().toRequestBody(JSON_TYPE))
        .build()

    try {
         client.newCall(request).execute().use { response ->
             val body = response.body?.string() ?: return null
             val json = JSONObject(body)
             val jobs = json.optJSONArray("jobs")
             if (jobs != null) {
                 for(i in 0 until jobs.length()) {
                     val job = jobs.getJSONObject(i)
                     // We assume the job named 'build' contains the artifact
                     if (job.optString("name").contains("build", ignoreCase = true)) {
                         return job.optLong("id")
                     }
                 }
                 // Fallback: Return first job if no specific name matches
                 if (jobs.length() > 0) return jobs.getJSONObject(0).optLong("id")
             }
         }
    } catch(e: Exception) { e.printStackTrace() }
    return null
}

// FETCH LOGS AND EXTRACT URL
fun fetchArtifactUrl(repo: String, jobId: Long): String? {
    val jsonBody = JSONObject().put("action", "fetch_logs").put("job_id", jobId).put("repo", repo)
    val request = Request.Builder()
        .url(SUPABASE_URL)
        .addHeader("Authorization", "Bearer $ANON_KEY")
        .post(jsonBody.toString().toRequestBody(JSON_TYPE))
        .build()

    try {
        client.newCall(request).execute().use { response ->
            val logs = response.body?.string() ?: return null
            // Regex to find: "Artifact download URL: https://..."
            val regex = Regex("Artifact download URL:\\s*(https://[^\\s]+)")
            val match = regex.find(logs)
            return match?.groupValues?.get(1)
        }
    } catch (e: Exception) { e.printStackTrace() }
    return null
}

