package com.gboard.clone

import android.content.Context
import android.util.Log
import com.darkrockstudios.symspellkt.api.SymSpell
import com.darkrockstudios.symspellkt.common.Verbosity
import com.darkrockstudios.symspellkt.impl.core.InMemorySymSpellBuilder
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import java.io.File

class TextPredictor(private val context: Context) {

    // Engine Configuration
    private var symSpell: SymSpell? = null
    private val maxEditDistance = 2 // Standard for mobile typing

    // User Data
    private val userDictFile = File(context.filesDir, "user_learning.txt")

    // State
    @Volatile private var isLoaded = false

    fun loadDictionary() {
        if (isLoaded) return

        Thread {
            try {
                // 1. Initialize SymSpell Engine
                // Strategy: Speed over memory. Prefix Length 7 is aggressive but fast.
                val builder = InMemorySymSpellBuilder()
                    .setMaxDictionaryEditDistance(maxEditDistance)
                    .setPrefixLength(7) 
                    .setCountThreshold(1)

                symSpell = builder.build()

                Log.d("TextPredictor", "Loading Dictionary...")

                // 2. Load Standard Dictionary (Raw Resource)
                // Expects file at: app/src/main/res/raw/dictionary.txt
                val resId = context.resources.getIdentifier("dictionary", "raw", context.packageName)
                if (resId != 0) {
                    context.resources.openRawResource(resId).use { stream ->
                        stream.bufferedReader().forEachLine { line ->
                            // PARSE: "word frequency"
                            // Example: "the 23135851162"
                            val parts = line.split(" ")
                            if (parts.size >= 2) {
                                val word = parts[0]
                                val count = parts[1].toLongOrNull() ?: 1L
                                symSpell?.createDictionaryEntry(word, count)
                            }
                        }
                    }
                } else {
                    Log.e("TextPredictor", "DICTIONARY NOT FOUND. Please check res/raw/dictionary.txt")
                }

                // 3. Load User Learned Words
                if (userDictFile.exists()) {
                    userDictFile.forEachLine { word ->
                        // Give user words a massive frequency boost so they override defaults
                        symSpell?.createDictionaryEntry(word, Long.MAX_VALUE / 2)
                    }
                }

                isLoaded = true
                Log.d("TextPredictor", "SymSpell Loaded Successfully.")

            } catch (e: Exception) {
                Log.e("TextPredictor", "Failed to load dictionary", e)
            }
        }.start()
    }

    fun learnWord(word: String) {
        if (word.isBlank() || !isLoaded) return

        // Add to live memory immediately
        symSpell?.createDictionaryEntry(word, Long.MAX_VALUE / 2)

        // Persist to disk
        Thread {
            try {
                userDictFile.appendText("$word\n")
            } catch (e: Exception) {
                e.printStackTrace()
            }
        }.start()
    }

    suspend fun predict(input: String, isAmharic: Boolean): List<String> {
        if (!isLoaded || symSpell == null || input.isBlank()) return emptyList()

        return withContext(Dispatchers.Default) {
            // AMHARIC TODO: Load Amharic dictionary into SymSpell
            // For now, we return empty to prevent English autocorrect from interfering with Amharic typing
            if (isAmharic) return@withContext emptyList()

            val suggestions = mutableListOf<String>()

            // Lookup with Max Edit Distance (2)
            // Verbosity.CLOSEST ensures we get the best matches first (Speed Optimization)
            val results = symSpell!!.lookup(
                input, 
                Verbosity.CLOSEST, 
                maxEditDistance
            )

            if (results.isNotEmpty()) {
                results.forEach { item ->
                    suggestions.add(item.term)
                }
            }

            // Deduplicate and limit to top 3
            suggestions.distinct().take(3)
        }
    }
}

