        try {
            def zip = new java.util.zip.ZipFile(aarFile)
            def classesEntry = zip.getEntry("classes.jar")
            if (classesEntry != null) {
                def stream = zip.getInputStream(classesEntry)
                def tempJar = File.createTempFile("classes", ".jar")
                tempJar.withOutputStream { it << stream }

                def jarFile = new java.util.zip.ZipFile(tempJar)
                jarFile.entries().each { entry ->
                    if (entry.name.endsWith(".class")) {
                        println "CLASS: ${entry.name}"
                    }
                }
                tempJar.delete()
            } else {
                println "ERROR: classes.jar not found inside AAR!"
                zip.entries().each { println " - ${it.name}" }
            }
        } catch (Exception e) {
            println "ERROR INSPECTING AAR: ${e.message}"
        }
        println "======================================\n"
    }
}
