import android.content.Context
import android.util.Log
import com.darkrockstudios.symspellkt.impl.SymSpell
import com.darkrockstudios.symspellkt.common.SpellCheckSettings
import com.darkrockstudios.symspellkt.common.DamerauLevenshteinDistance
import com.darkrockstudios.symspellkt.impl.InMemoryDictionaryHolder
import com.darkrockstudios.symspellkt.common.Murmur3HashFunction
import com.darkrockstudios.symspellkt.common.Verbosity
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import java.io.File

class TextPredictor(private val context: Context) {

    // Engine Configuration
    @Volatile private var symSpell: SymSpell? = null
    private val maxEditDistance = 2.0 

    // User Data
    private val userDictFile = File(context.filesDir, "user_learning.txt")

    // State
    @Volatile private var isLoaded = false

    fun loadDictionary() {
        if (isLoaded) return

        Thread {
            try {
                // 1. Initialize SymSpell Engine (v3.4.0 Component Init)
                // FIX: Use positional arguments or correct parameter names if known.
                // Assuming order: maxEditDistance, prefixLength, countThreshold
                val settings = SpellCheckSettings(
                    maxDictionaryEditDistance = 2,
                    prefixLength = 7,
                    countThreshold = 1
                )
                val distance = DamerauLevenshteinDistance()
                val holder = InMemoryDictionaryHolder(settings)
                val hash = Murmur3HashFunction()

                // FIX: Constructor requires hashFunction in this version
                val engine = SymSpell(settings, distance, holder, hash)

                Log.d("TextPredictor", "Loading Dictionary...")

                // 2. Load Standard Dictionary
                val resId = context.resources.getIdentifier("dictionary", "raw", context.packageName)
                if (resId != 0) {
                    context.resources.openRawResource(resId).use { stream ->
                        stream.bufferedReader().forEachLine { line ->
                            val parts = line.split(" ")
                            if (parts.size >= 2) {
                                val word = parts[0]
                                val count = parts[1].toIntOrNull() ?: 1
                                engine.createDictionaryEntry(word, count)
                            }
                        }
                    }
                } else {
                    Log.e("TextPredictor", "DICTIONARY NOT FOUND. Please check res/raw/dictionary.txt")
                }

                // 3. Load User Learned Words
                if (userDictFile.exists()) {
                    userDictFile.forEachLine { word ->
                        engine.createDictionaryEntry(word, Int.MAX_VALUE / 2)
                    }
                }

                // Assign to global variable only after full initialization
                symSpell = engine
                isLoaded = true
                Log.d("TextPredictor", "SymSpell Loaded Successfully.")

            } catch (e: Exception) {
                Log.e("TextPredictor", "Failed to load dictionary", e)
            }
        }.start()
    }

    fun learnWord(word: String) {
        if (word.isBlank()) return

        // Capture local ref to avoid race conditions
        val engine = symSpell ?: return

        // Add to live memory
        engine.createDictionaryEntry(word, Int.MAX_VALUE / 2)

        // Persist to disk
        Thread {
            try {
                userDictFile.appendText("$word\n")
            } catch (e: Exception) {
                e.printStackTrace()
            }
        }.start()
    }

    suspend fun predict(input: String, isAmharic: Boolean): List<String> {
        // Capture local immutable reference to satisfy Kotlin smart-cast requirements
        val engine = symSpell
        if (!isLoaded || engine == null || input.isBlank()) return emptyList()

        return withContext(Dispatchers.Default) {
            if (isAmharic) return@withContext emptyList()

            val suggestions = mutableListOf<String>()

            try {
                // Use local 'engine' ref (safe)
                val results = engine.lookup(
                    input, 
                    Verbosity.Closest, 
                    maxEditDistance
                )

                if (results.isNotEmpty()) {
                    results.forEach { item ->
                        suggestions.add(item.term)
                    }
                }
            } catch (e: Exception) {
                e.printStackTrace()
            }

            suggestions.distinct().take(3)
        }
    }
}

