                val resId = context.resources.getIdentifier("dictionary", "raw", context.packageName)
                if (resId != 0) {
                    context.resources.openRawResource(resId).use { stream ->
                        var loadedCount = 0
                        stream.bufferedReader().forEachLine { line ->
                            val parts = line.split(" ")
                            if (parts.size >= 2) {
                                val word = parts[0]

                                // BUG FIX: Large corpuses have counts > Int.MAX_VALUE.
                                // Using toIntOrNull() returns null for these, defaulting to 1.
                                // We must parse as Long, then clamp to Int.MAX_VALUE.
                                val rawCount = parts[1].toLongOrNull() ?: 1L
                                val count = rawCount.coerceAtMost(Int.MAX_VALUE.toLong()).toInt()

                                engine.createDictionaryEntry(word, count)

                                // Load top frequent words for Auto-Complete
                                if (loadedCount < 5000 && word.length > 2) {
                                    tempCompletion.add(word)
                                }
                                loadedCount++
                            }
                        }
                    }
                }

                // Load User Words
                if (userDictFile.exists()) {
                    userDictFile.forEachLine { word ->
                        engine.createDictionaryEntry(word, Int.MAX_VALUE)
                        tempCompletion.add(0, word) // User words -> High priority completion
                    }
                }

                // Commit
                completionList.clear()
                completionList.addAll(tempCompletion)
                symSpell = engine
                isLoaded = true
                Log.d("TextPredictor", "SymSpell Loaded.")

            } catch (e: Exception) {
                e.printStackTrace()
            }
        }.start()
    }

    fun learnWord(word: String) {
        if (word.isBlank()) return
        val engine = symSpell ?: return

        engine.createDictionaryEntry(word, Int.MAX_VALUE)
        completionList.add(0, word)

        Thread {
            try { userDictFile.appendText("$word\n") } catch (e: Exception) {}
        }.start()
    }

    suspend fun predict(input: String, isAmharic: Boolean): List<String> {
        val engine = symSpell
        if (!isLoaded || engine == null || input.isBlank()) return emptyList()

        return withContext(Dispatchers.Default) {
            if (isAmharic) return@withContext emptyList()

            val suggestions = mutableListOf<String>()
            val lowerInput = input.lowercase()
            val isCapitalized = input.first().isUpperCase()

            // 1. AUTO-CORRECT (Edit Distance)
            try {
                // Use lowercase for lookup to improve match rate
                val results = engine.lookup(lowerInput, Verbosity.Closest, maxEditDistance)
                results.forEach { suggestions.add(it.term) }
            } catch (e: Exception) { e.printStackTrace() }

            // 2. AUTO-COMPLETE (Prefix Match)
            // If we don't have enough suggestions, look for completions
            if (suggestions.size < 3) {
