        return withContext(Dispatchers.Default) {
            if (isAmharic) return@withContext emptyList()

            val term = input.lowercase()
            val candidates = mutableSetOf<String>()
            val rankedResults = ArrayList<String>()

            // STRATEGY 1: EXACT PREFIX (Autocomplete)
            // Input "th" -> "the", "that"
            val completions = trieSearch(term, 3)
            candidates.addAll(completions)

            // STRATEGY 2: SPATIAL CORRECTION (Fat Finger)
            // Input "rhi" (user meant "the"? 'r' is near 't', 'i' near 'e')
            // We perform a limited permutation if the word is short
            if (term.length in 3..6 && completions.isEmpty()) {
                 val spatialMatches = spatialPermutationSearch(term)
                 candidates.addAll(spatialMatches)
            }

            // STRATEGY 3: EDIT DISTANCE (SymSpell)
            // Catch-all for wild typos
            if (candidates.isEmpty()) {
                try {
                    val corrections = engine.lookup(term, Verbosity.Closest, maxEditDistance)
                    corrections.forEach { candidates.add(it.term) }
                } catch (e: Exception) {}
            }

