    private class TrieNode {
        val children = HashMap<Char, TrieNode>()
        var isEndOfWord = false
        var frequency: Long = 0
        var word: String? = null
    }

    private fun trieInsert(word: String, freq: Long) {
        var current = trieRoot
        for (char in word.lowercase()) {
            current = current.children.getOrPut(char) { TrieNode() }
        }
        current.isEndOfWord = true
        current.word = word
        if (freq > current.frequency) current.frequency = freq
    }

    private fun trieContains(word: String): Boolean {
        var current = trieRoot
        for (char in word.lowercase()) {
            current = current.children[char] ?: return false
        }
        return current.isEndOfWord
    }

    private fun trieSearch(prefix: String, limit: Int): List<String> {
        var current = trieRoot
        for (char in prefix.lowercase()) {
            current = current.children[char] ?: return emptyList()
        }

        // BFS/DFS for highest frequency words
        val results = PriorityQueue<Pair<String, Long>> { a, b -> 
            b.second.compareTo(a.second) 
        }
        collectWords(current, results)

        val list = mutableListOf<String>()
        while (results.isNotEmpty() && list.size < limit) {
            list.add(results.poll()!!.first)
        }
        return list
    }

    private fun collectWords(node: TrieNode, results: PriorityQueue<Pair<String, Long>>) {
        if (node.isEndOfWord) {
            results.add(Pair(node.word!!, node.frequency))
        }
        for ((_, child) in node.children) {
            collectWords(child, results)
        }
    }

    // === SPATIAL UTILITIES ===
    // A simplified 'Beam' that checks 1-char variations based on keyboard layout
    private fun spatialPermutationSearch(input: String): List<String> {
        val results = mutableListOf<String>()
        val chars = input.toCharArray()

        // Iterate through each char and try replacing it with a neighbor
        for (i in chars.indices) {
            val original = chars[i]
            val neighbors = keyboardNeighbors[original] ?: continue

            for (n in neighbors) {
                chars[i] = n
                val candidate = String(chars)
                // Check if this variation exists in Trie
                if (trieContains(candidate)) {
                    results.add(candidate)
                }
            }
            // Restore
            chars[i] = original
        }
        return results
    }
}

