                            val parts = line.trim().split("\\s+".toRegex())
                            if (parts.isNotEmpty()) {
                                val word = parts[0]
                                val count = if (parts.size >= 2) parts[1].toLongOrNull() ?: 100L else 100L

                                if (word.isNotEmpty()) {
                                    engine.createDictionaryEntry(word, count)
                                    trieInsert(word, count)
                                }
                            }
                        }
                    }
                }

