                if (userDictFile.exists()) {
                    userDictFile.forEachLine { line ->
                        val word = line.trim()
                        if (word.isNotEmpty()) {
                            val userFreq = 5000000000L 
                            engine.createDictionaryEntry(word, userFreq)
                            trieInsert(word, userFreq)
                        }
                    }
                }

