package com.gboard.clone

import android.content.Context
import android.util.Log
import com.darkrockstudios.symspellkt.impl.SymSpell
import com.darkrockstudios.symspellkt.common.Verbosity
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import java.io.File

/**
 * OPTIMIZED HYBRID PREDICTION ENGINE
 * 1. Branch-and-Bound Trie: Instant O(1) prefix lookups using cached frequencies.
 * 2. SymSpell: Edit-distance correction for typos.
 * 3. Spatial: QWERTY neighbor mapping.
 */
class TextPredictor(private val context: Context) {

    // === ENGINES ===
    private val trieRoot = TrieNode()
    @Volatile private var symSpell: SymSpell? = null
    private val maxEditDistance = 2.0

    // === STATE ===
    @Volatile private var isLoaded = false
    private val userDictFile = File(context.filesDir, "user_learning.txt")

    // === SPATIAL MODEL ===
    private val keyboardNeighbors = mapOf(
        'q' to "wa", 'w' to "qase", 'e' to "wrsd", 'r' to "etdf", 't' to "ryfg", 'y' to "tugh", 'u' to "yijh", 'i' to "uojk", 'o' to "ipkl", 'p' to "ol",
        'a' to "qwsz", 's' to "weadzx", 'd' to "ersfxc", 'f' to "rtdgcv", 'g' to "tyfhvb", 'h' to "yugjbn", 'j' to "uihknm", 'k' to "iojlm", 'l' to "opk",
        'z' to "asx", 'x' to "sdzc", 'c' to "dfxv", 'v' to "fgcb", 'b' to "ghvn", 'n' to "hjbm", 'm' to "jkn"
    )

    // === INITIALIZATION ===
    fun loadDictionary() {
        if (isLoaded) return

        Thread {
            try {
                val engine = SymSpell()
                Log.d("TextPredictor", "Loading Dictionary...")

                // 1. Load Standard Dictionary
                val resId = context.resources.getIdentifier("dictionary", "raw", context.packageName)
                if (resId != 0) {
                    context.resources.openRawResource(resId).use { stream ->
                        stream.bufferedReader().forEachLine { line ->
                            val parts = line.trim().split("\\s+".toRegex())
                            if (parts.isNotEmpty()) {
                                val word = parts[0]
                                val count = if (parts.size >= 2) parts[1].toLongOrNull() ?: 100L else 100L

                                if (word.isNotEmpty()) {
                                    engine.createDictionaryEntry(word, count)
                                    trieInsert(word, count)
                                }
                            }
                        }
                    }
                }

                // 2. Load User Learned Words (Boosted)
                if (userDictFile.exists()) {
                    userDictFile.forEachLine { line ->
                        val word = line.trim()
                        if (word.isNotEmpty()) {
                            val userFreq = 5000000000L 
                            engine.createDictionaryEntry(word, userFreq)
                            trieInsert(word, userFreq)
                        }
                    }
                }

                symSpell = engine
                isLoaded = true
                Log.d("TextPredictor", "Optimized Engine Loaded.")
            } catch (e: Exception) {
                Log.e("TextPredictor", "Failed to load dictionary", e)
            }
        }.start()
    }

    fun learnWord(word: String) {
        if (word.isBlank()) return
        val engine = symSpell ?: return
        val learnFreq = Int.MAX_VALUE.toLong()

        // Update Memory
        engine.createDictionaryEntry(word, learnFreq)
        trieInsert(word, learnFreq)

        // Persist
        Thread {
            try { userDictFile.appendText("$word\n") } catch (e: Exception) {}
        }.start()
    }

    // === PREDICTION ===
    suspend fun predict(input: String, isAmharic: Boolean): List<String> {
        val engine = symSpell
        if (!isLoaded || engine == null) return emptyList()

        return withContext(Dispatchers.Default) {
            if (isAmharic) return@withContext emptyList()

            // 1. ZERO-LATENCY FALLBACK (Next Word Prediction)
            // If input is empty (cursor at start or after space), return top 3 common words.
            if (input.isBlank()) {
                return@withContext trieSearch("", 3)
            }

            val term = input.lowercase()
            val candidates = mutableSetOf<String>()
            val rankedResults = ArrayList<String>()

            // 2. OPTIMIZED TRIE SEARCH (Autocomplete)
            val completions = trieSearch(term, 3)
            candidates.addAll(completions)

            // 3. SPATIAL PERMUTATION (Fat Finger)
            // Only if we don't have enough confidence in completions
            if (term.length in 3..6 && completions.size < 2) {
                 val spatialMatches = spatialPermutationSearch(term)
                 candidates.addAll(spatialMatches)
            }

            // 4. SYM SPELL (Correction)
            // Fallback for gross errors
            if (candidates.isEmpty()) {
                try {
                    val corrections = engine.lookup(term, Verbosity.Closest, maxEditDistance)
                    corrections.forEach { candidates.add(it.term) }
                } catch (e: Exception) {}
            }

            // 5. RANKING
            val isTypedValid = trieContains(term)
            rankedResults.addAll(candidates)

            if (isTypedValid) {
                rankedResults.remove(term)
                rankedResults.add(0, term)
            }

            rankedResults.distinct().take(3)
        }
    }

    // === OPTIMIZED TRIE ===
    private class TrieNode {
        val children = HashMap<Char, TrieNode>()
        var isEndOfWord = false
        var frequency: Long = 0
        var word: String? = null
        var maxSubtreeFrequency: Long = 0 // Branch-and-Bound Key
    }

    private fun trieInsert(word: String, freq: Long) {
        var current = trieRoot
        if (freq > current.maxSubtreeFrequency) current.maxSubtreeFrequency = freq

        for (char in word.lowercase()) {
            current = current.children.getOrPut(char) { TrieNode() }
            // Bubble up frequency info during insert
            if (freq > current.maxSubtreeFrequency) current.maxSubtreeFrequency = freq
        }
        current.isEndOfWord = true
        current.word = word
        if (freq > current.frequency) current.frequency = freq
    }

    private fun trieContains(word: String): Boolean {
        var current = trieRoot
        for (char in word.lowercase()) {
            current = current.children[char] ?: return false
        }
        return current.isEndOfWord
    }

    private fun trieSearch(prefix: String, limit: Int): List<String> {
        var current = trieRoot
        // 1. Navigate to prefix
        for (char in prefix.lowercase()) {
            current = current.children[char] ?: return emptyList()
        }

        // 2. Greedy Search
        val results = ArrayList<String>()
        searchRecursive(current, results, limit)
        return results
    }

    // Recursive DFS with Priority Sorting (Greedy)
    // This is vastly faster than checking all nodes because we visit the highest-freq branches first
    // and stop immediately when we have enough results.
    private fun searchRecursive(node: TrieNode, results: MutableList<String>, limit: Int) {
        if (results.size >= limit) return

        if (node.isEndOfWord && node.word != null) {
            results.add(node.word!!)
        }

        // Optimization: Sort children by their potential. Visit the 'hottest' path first.
        // If the dictionary is large, this prevents visiting thousands of 'dud' nodes.
        val sortedChildren = node.children.values.sortedByDescending { it.maxSubtreeFrequency }

        for (child in sortedChildren) {
            if (results.size >= limit) return
            searchRecursive(child, results, limit)
        }
    }

    // === SPATIAL UTILITIES ===
    private fun spatialPermutationSearch(input: String): List<String> {
        val results = mutableListOf<String>()
        val chars = input.toCharArray()
        for (i in chars.indices) {
            val original = chars[i]
            val neighbors = keyboardNeighbors[original] ?: continue
            for (n in neighbors) {
                chars[i] = n
                val candidate = String(chars)
                if (trieContains(candidate)) results.add(candidate)
            }
            chars[i] = original
        }
        return results
    }
}

