class TextPredictor(private val context: Context) {

    private val trieRoot = TrieNode()
    @Volatile private var symSpell: SymSpell? = null
    private val bigrams = HashMap<String, MutableList<Pair<String, Long>>>()

    // SEMANTIC EMOJI MAP
    private val emojiMap = mapOf(
        "fire" to "🔥", "lit" to "🔥", "love" to "❤️", "heart" to "❤️", 
        "cool" to "😎", "laugh" to "😂", "lol" to "😂", "ok" to "👌",
        "yes" to "✅", "party" to "🥳", "birthday" to "🎂", "star" to "⭐"
    )

    // SHORTCUT MAP
    private val shortcuts = mapOf(
        "@@" to "user@example.com",
        "brb" to "Be right back",
        "omw" to "On my way!",
        "hw" to "Hello World!"
    )

    @Volatile private var isLoaded = false
    private val userDictFile = File(context.filesDir, "user_learning.txt")

    fun loadDictionary() {
        if (isLoaded) return
        Thread {
            try {
                val engine = SymSpell()

                // 1. Load Unigrams (Dictionary)
                val dictId = context.resources.getIdentifier("dictionary", "raw", context.packageName)
                if (dictId != 0) {
                    context.resources.openRawResource(dictId).use { stream ->
                        stream.bufferedReader().forEachLine { line ->
                            val parts = line.trim().split("\\s+".toRegex())
                            if (parts.size >= 2) {
                                val word = parts[0]
                                val freq = parts[1].toLongOrNull() ?: 100L
                                engine.createDictionaryEntry(word, freq.toDouble())
                                trieInsert(word, freq)
                            }
                        }
                    }
                }

                // 2. Load Bigrams (Context)
                val bigramId = context.resources.getIdentifier("bigrams", "raw", context.packageName)
                if (bigramId != 0) {
                    context.resources.openRawResource(bigramId).use { stream ->
                        stream.bufferedReader().forEachLine { line ->
                            val parts = line.trim().split("\\s+".toRegex())
                            if (parts.size >= 3) {
                                val w1 = parts[0].lowercase()
                                val w2 = parts[1]
                                val freq = parts[2].toLongOrNull() ?: 10L
                                bigrams.getOrPut(w1) { mutableListOf() }.add(Pair(w2, freq))
                            }
                        }
                    }
                    // Sort bigrams by frequency once at load time
                    bigrams.values.forEach { it.sortByDescending { p -> p.second } }
                }

                symSpell = engine
                isLoaded = true
            } catch (e: Exception) { Log.e("TextPredictor", "Load Error", e) }
        }.start()
    }

    suspend fun predict(input: String, prevWord: String?, isAmharic: Boolean): List<String> {
        if (!isLoaded || isAmharic) return emptyList()

        return withContext(Dispatchers.Default) {
            val term = input.lowercase()
            val results = mutableListOf<String>()

            // 1. SHORTCUTS (Highest Priority)
