            // 2. NEXT-WORD PREDICTION (Bigrams)
            // If user just finished a word (input is empty), suggest based on prevWord
            if (term.isEmpty() && prevWord != null) {
                bigrams[prevWord.lowercase()]?.take(3)?.forEach { results.add(it.first) }
            }

            // 3. PREFIX COMPLETION (Trie)
            if (term.isNotEmpty()) {
                val completions = trieSearch(term, 3)
                results.addAll(completions)
            }

            // 4. EMOJI SYNTHESIS
            // If any suggested word has an emoji, append it
            val finalResults = results.distinct().map { word ->
                val emoji = emojiMap[word.lowercase()]
                if (emoji != null) "$word $emoji" else word
            }

            finalResults.take(3)
        }
    }

    fun learnWord(word: String) {
        val engine = symSpell ?: return
        val freq = 5000000000L
        engine.createDictionaryEntry(word, freq.toDouble())
        trieInsert(word, freq)
        Thread { try { userDictFile.appendText("$word\n") } catch (e: Exception) {} }.start()
    }

    private class TrieNode {
        val children = HashMap<Char, TrieNode>()
        var isEndOfWord = false
        var frequency: Long = 0
        var word: String? = null
        var maxSubtreeFreq: Long = 0
    }

    private fun trieInsert(word: String, freq: Long) {
        var current = trieRoot
        if (freq > current.maxSubtreeFreq) current.maxSubtreeFreq = freq
        for (char in word.lowercase()) {
            current = current.children.getOrPut(char) { TrieNode() }
            if (freq > current.maxSubtreeFreq) current.maxSubtreeFreq = freq
        }
        current.isEndOfWord = true
        current.word = word
        current.frequency = freq
    }

    private fun trieSearch(prefix: String, limit: Int): List<String> {
        var current = trieRoot
        for (char in prefix.lowercase()) {
            current = current.children[char] ?: return emptyList()
        }
        val results = mutableListOf<String>()
        searchRecursive(current, results, limit)
        return results
    }

    private fun searchRecursive(node: TrieNode, results: MutableList<String>, limit: Int) {
        if (results.size >= limit) return
        if (node.isEndOfWord && node.word != null) results.add(node.word!!)
        val sorted = node.children.values.sortedByDescending { it.maxSubtreeFreq }
        for (child in sorted) {
            if (results.size >= limit) return
            searchRecursive(child, results, limit)
        }
    }
}

