                Log.d("TextPredictor", "Starting Dictionary Load...")

                // 1. LOAD UNIGRAMS (Standard Dictionary)
                loadUnigrams()

                // 2. LOAD BIGRAMS (Next Word Context)
                loadBigrams()

                isLoaded = true
                Log.d("TextPredictor", "Engine Ready. Time: ${System.currentTimeMillis() - t0}ms")
            } catch (e: Exception) {
                Log.e("TextPredictor", "Load Failed", e)
            }
        }.start()
    }

    private fun loadUnigrams() {
        val resId = context.resources.getIdentifier("dictionary", "raw", context.packageName)
        if (resId == 0) return

        context.resources.openRawResource(resId).use { stream ->
            stream.bufferedReader().forEachLine { line ->
                val parts = line.trim().split("\\s+".toRegex())
                if (parts.isNotEmpty()) {
                    val word = parts[0]
                    val freq = if (parts.size >= 2) parts[1].toLongOrNull() ?: 100L else 100L
                    if (word.length in 1..30) insertTrie(word, freq)
                }
            }
        }
    }

    private fun loadBigrams() {
        // Uses a Min-Heap Accumulator to keep only Top 3 per word during parsing
        val tempMap = HashMap<String, PriorityQueue<Pair<Long, String>>>()

        // Try to find bigrams.txt
        val resId = context.resources.getIdentifier("bigrams", "raw", context.packageName)
        if (resId == 0) {
            Log.w("TextPredictor", "bigrams.txt not found in res/raw/")
            return
        }

        context.resources.openRawResource(resId).use { stream ->
            stream.bufferedReader().forEachLine { line ->
                // Format: "word1 word2 frequency"
                val parts = line.trim().split(" ")
                if (parts.size >= 3) {
                    val w1 = parts[0].lowercase()
                    val w2 = parts[1]
                    val freq = parts[2].toLongOrNull() ?: 0L

                    if (freq > 1000) { // Prune very low freq noise
                        val heap = tempMap.getOrPut(w1) { 
                            PriorityQueue { a, b -> a.first.compareTo(b.first) } // Min-Heap
                        }

                        heap.add(freq to w2)
                        if (heap.size > 3) heap.poll() // Remove smallest
                    }
                }
            }
        }

        // Finalize: Convert Heap to Sorted List
        tempMap.forEach { (key, heap) ->
            val sorted = heap.sortedByDescending { it.first }.map { it.second }
            bigramMap[key] = sorted
        }
    }

    fun learnWord(word: String) {
        // Boost frequency dynamically
        insertTrie(word, Long.MAX_VALUE)
    }

    // === CORE PREDICTION API ===
    suspend fun predict(currentInput: String, previousWord: String, isAmharic: Boolean): List<String> {
        if (!isLoaded) return listOf("Loading...")
        if (isAmharic) return emptyList() // Amharic handled by simple transliterator

        return withContext(Dispatchers.Default) {
            // CASE 1: ZERO STATE / NEXT WORD PREDICTION
            // If user input is empty (or just cursor moved), use Previous Word context
            if (currentInput.isBlank()) {
                return@withContext bigramMap[previousWord.lowercase()] 
                    ?: listOf("The", "I", "Hello") // Fallback Sentence Starters
            }

            // CASE 2: ACTIVE TYPING (Fuzzy Search)
            // "Fight to the end" logic
            val results = searchFuzzy(currentInput.lowercase())

            // Sort by Score (Frequency / Cost)
            results.sortedByDescending { it.score }
                   .map { it.word }
                   .distinct()
                   .take(3)
        }
    }

    // === FUZZY TRIE SEARCH ===

    data class SearchResult(val word: String, val score: Double)

    private fun searchFuzzy(target: String): List<SearchResult> {
        val results = ArrayList<SearchResult>()
        // Dynamic Edit Distance: Allow more errors for longer words
        val maxCost = when (target.length) {
            in 0..3 -> 1.0
            in 4..7 -> 2.0
            else -> 3.0
        }

        recursiveWalk(trieRoot, target, 0, 0.0, maxCost, results)

        // If strict search failed, try "Skeleton Search" (Vowel Removal) - fallback
        // (Implemented simply by being permissive in the walk)

        return results
    }

    private fun recursiveWalk(
        node: TrieNode, 
        target: String, 
        index: Int, 
        cost: Double, 
        maxCost: Double, 
        results: MutableList<SearchResult>
    ) {
        // Pruning
        if (cost > maxCost) return

        // Base Case: Reached end of prediction path
        // We allow partial matches (autocomplete) so we don't strictly enforce index == target.length
        // But we penalize "short" matches if the target is much longer
        if (node.isEndOfWord) {
             // Calculate final score based on how much of the target we covered
             val lenDiff = Math.abs(target.length - index)
             val finalCost = cost + (lenDiff * 0.5) // Light penalty for length mismatch

             if (finalCost <= maxCost) {
                 // SCORE FORMULA: Frequency / (Cost + 1)^2
                 // High frequency dominates, but high cost punishes heavily
                 val score = node.frequency.toDouble() / Math.pow(finalCost + 1.0, 3.0)
                 results.add(SearchResult(node.word!!, score))
             }
        }

        // Recursion

        // 1. INSERTION (User missed a char)
        // We stay at 'index' in target, but move to children in Trie
        // Cost: 1.0
        if (cost + 1.0 <= maxCost) {
             node.children.forEach { (_, child) ->
                 recursiveWalk(child, target, index, cost + 1.0, maxCost, results)
             }
        }

        if (index >= target.length) return

        val char = target[index]

        // 2. MATCH & SUBSTITUTION
        node.children.forEach { (childChar, childNode) ->
            var newCost = cost
            if (childChar == char) {
                // Match: Cost 0
            } else {
                // Mismatch: Check spatial map
                val nearby = neighbors[char]?.contains(childChar) == true
                newCost += if (nearby) 0.5 else 1.0
            }
            recursiveWalk(childNode, target, index + 1, newCost, maxCost, results)
        }

        // 3. DELETION (User typed extra char)
        // Skip target char, stay at current Node
        recursiveWalk(node, target, index + 1, cost + 1.0, maxCost, results)
    }

    // === TRIE CORE ===
    class TrieNode {
        val children = HashMap<Char, TrieNode>(4)
        var isEndOfWord = false
        var frequency: Long = 0
        var word: String? = null
    }

    private fun insertTrie(word: String, freq: Long) {
        var node = trieRoot
        for (c in word) {
            node = node.children.getOrPut(c) { TrieNode() }
        }
        node.isEndOfWord = true
        node.word = word
        // Keep highest frequency found for this word
        if (freq > node.frequency) node.frequency = freq
    }
}

